{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "action": "incident.create",
        "resource": "slack.channel",
        "context": "incident_response_workflow"
      },
      "depends_on": []
    },
    {
      "tool": "datadog.list_alerts",
      "arguments": {
        "filter": {
          "status": "triggered",
          "priority": ["P1", "P2"]
        },
        "limit": 10
      },
      "depends_on": [1]
    },
    {
      "tool": "datadog.query_metric",
      "arguments": {
        "query": "avg:system.cpu.user{*} by {service}, avg:system.mem.used{*} by {service}, sum:trace.request.errors{*} by {service}",
        "from": "now-30m",
        "to": "now",
        "context": "identify_affected_service_from_alerts_$2.alerts"
      },
      "depends_on": [2]
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "access_logs",
        "filter": {
          "timestamp": { "$gte": "now-30m" },
          "level": { "$in": ["ERROR", "CRITICAL", "FATAL"] }
        },
        "projection": {
          "service_name": 1,
          "error_code": 1,
          "stack_trace": 1,
          "timestamp": 1,
          "severity": 1
        },
        "limit": 50,
        "sort": { "timestamp": -1 }
      },
      "depends_on": [2]
    },
    {
      "tool": "sql.postgres.query",
      "arguments": {
        "query": "SELECT service_name, COUNT(*) AS error_count, MAX(severity) AS max_severity, MIN(timestamp) AS first_seen, MAX(timestamp) AS last_seen FROM access_logs WHERE timestamp >= NOW() - INTERVAL '30 minutes' AND level IN ('ERROR', 'CRITICAL', 'FATAL') GROUP BY service_name ORDER BY error_count DESC LIMIT 10"
      },
      "depends_on": [2]
    },
    {
      "tool": "pagerduty.create_incident",
      "arguments": {
        "title": "Automated Incident: Service Degradation Detected via Datadog Alerts",
        "severity": "high",
        "service": "$2.alerts[0].service",
        "body": {
          "type": "incident_body",
          "details": "Incident automatically opened based on triggered Datadog alerts. Affected alerts: $2.alerts. Top error service from access logs: $5.results[0].service_name with $5.results[0].error_count errors. Max severity: $5.results[0].max_severity. First seen: $5.results[0].first_seen."
        },
        "escalation_policy": "default"
      },
      "depends_on": [1, 2, 5]
    },
